const dimensions = data.dimension;

const results = [];

const freqKeys = Object.keys(dimensions.freq.category.index);
const unitKeys = Object.keys(dimensions.unit.category.index);
const iccsKeys = Object.keys(dimensions.iccs.category.index);
const geoKeys = Object.keys(dimensions.geo.category.index);
const timeKeys = Object.keys(dimensions.time.category.index);

for (const freq of freqKeys) {
  const i_freq = dimensions.freq.category.index[freq];
  for (const unit of unitKeys) {
    const i_unit = dimensions.unit.category.index[unit];
    for (const iccs of iccsKeys) {
      const i_iccs = dimensions.iccs.category.index[iccs];
      const iccsLabel = dimensions.iccs.category.label[iccs] || iccs;
      for (const geo of geoKeys) {
        const i_geo = dimensions.geo.category.index[geo];
        const geoName = dimensions.geo.category.label[geo] || geo;
        for (const time of timeKeys) {
          const i_time = dimensions.time.category.index[time];

          const idx = i_freq * (size[1] * size[2] * size[3] * size[4]) +
                      i_unit * (size[2] * size[3] * size[4]) +
                      i_iccs * (size[3] * size[4]) +
                      i_geo * size[4] +
                      i_time;

          const val = values[idx.toString()];
          if (val !== undefined && val !== null) {
            results.push({
              geo_code: geo,
              geo_name: geoName,
              year: parseInt(time, 10),
              offence_category: iccsLabel,
              crime_count: val,
              unit: unit
            });
          }
        }
      }
    }
  }
}
return results;
